import React, { useState, useEffect, useCallback } from 'react';
import { useAuth } from '../context/AuthContext';
import { tasksAPI } from '../services/api';
import { DEPARTMENTS, DEADLINE_CONFIG } from '../utils/helpers';
import Sidebar from '../components/Sidebar';
import TaskCard from '../components/TaskCard';
import TaskForm from '../components/TaskForm';

const DEPT_LIST = Object.keys(DEPARTMENTS);
const STATUS_LIST = ['', 'Pending', 'In Progress', 'Completed', 'On Hold'];
const PRIORITY_LIST = ['', 'Critical', 'High', 'Medium', 'Low'];

export default function DashboardPage() {
  const { user } = useAuth();

  const [tasks, setTasks] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [search, setSearch] = useState('');
  const [deptFilter, setDeptFilter] = useState('');
  const [statusFilter, setStatusFilter] = useState('');
  const [priorityFilter, setPriorityFilter] = useState('');
  const [showForm, setShowForm] = useState(false);
  const [mobileOpen, setMobileOpen] = useState(false);
  const [view, setView] = useState('cards');
  const [lastSync, setLastSync] = useState(null);

  const fetchTasks = useCallback(async () => {
    setLoading(true);
    setError('');
    try {
      const res = await tasksAPI.getTasks(search, deptFilter);
      setTasks(res?.data || []);
      setLastSync(new Date());
    } catch (err) {
      setError(err?.response?.data?.message || 'Failed to load tasks from Google Sheets');
    } finally {
      setLoading(false);
    }
  }, [search, deptFilter]);

  useEffect(() => {
    fetchTasks();
  }, [fetchTasks]);

  const filteredTasks = tasks.filter(t => {
    if (!t) return false;
    if (statusFilter && t.status !== statusFilter) return false;
    if (priorityFilter && t.priority !== priorityFilter) return false;
    return true;
  });

  const stats = {
    total: tasks.length,
    completed: tasks.filter(t => t?.status === 'Completed').length,
    overdue: tasks.filter(t => t?.deadlineStatus === 'overdue').length,
    urgent: tasks.filter(t => t?.deadlineStatus === 'urgent').length,
    inProgress: tasks.filter(t => t?.status === 'In Progress').length,
  };

  const grouped = filteredTasks.reduce((acc, t) => {
    const d = t?._department || 'Unknown';
    if (!acc[d]) acc[d] = [];
    acc[d].push(t);
    return acc;
  }, {});

  const canCreate = user?.role === 'manager' || user?.role === 'admin';

  return (
    <div style={{ display: 'flex', minHeight: '100vh' }}>
      <Sidebar mobileOpen={mobileOpen} onClose={() => setMobileOpen(false)} />

      <main style={{ flex: 1 }}>
        <div style={{ padding: 20 }}>
          <h2>Task Dashboard</h2>

          <button onClick={fetchTasks}>Refresh</button>

          {loading && <p>Loading...</p>}
          {error && <p style={{ color: 'red' }}>{error}</p>}

          {!loading && !error && filteredTasks.length === 0 && (
            <p>No Tasks Found</p>
          )}

          {!loading && !error && view === 'cards' && (
            <div>
              {Object.entries(grouped).map(([dept, dTasks]) => (
                <div key={dept}>
                  <h3>{dept}</h3>
                  {dTasks.map(task => (
                    <TaskCard
                      key={`${task._department}-${task._rowIndex}`}
                      task={task}
                      onTaskUpdated={fetchTasks}
                      isManager={canCreate}
                    />
                  ))}
                </div>
              ))}
            </div>
          )}

          {!loading && !error && view === 'list' && (
            <table>
              <thead>
                <tr>
                  <th>Title</th>
                  <th>Department</th>
                  <th>Status</th>
                </tr>
              </thead>
              <tbody>
                {filteredTasks.map(task => (
                  <tr key={`${task._department}-${task._rowIndex}`}>
                    <td>{task.title}</td>
                    <td>{task._department}</td>
                    <td>{task.status}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      </main>

      {showForm && (
        <TaskForm
          onSuccess={() => {
            setShowForm(false);
            fetchTasks();
          }}
          onCancel={() => setShowForm(false)}
        />
      )}
    </div>
  );
}
